// POST /api/design — OWNED by Dev B
// Assembles a complete DesignResult for the demo:
// - For demo houses (brandenburg/hamburg/ruhr): reads pre-baked roof geometry
//   from public/baked/{houseId}-analysis.json (Dev D's analyze-roof.ts output).
// - For custom addresses (`houseId === 'custom'`): synthesises a plausible
//   roof geometry from lat/lng + houseSizeSqm so the demo works on any address
//   the jury types in. The brief explicitly authorises "estimate the space
//   available" as a fallback when on-the-fly photogrammetry is too slow.
// - Applies isJumelee divisor (semi-detached roof is shared with neighbour).
// - Calls k-NN sizing on 1620 Reonic projects.
// - Computes financials (price, payback, CO2).
// - Returns the full BOM the UI / 3D scene consumes.

import { promises as fs } from 'node:fs';
import path from 'node:path';
import { NextRequest, NextResponse } from 'next/server';

import { recommendSystem } from '@/lib/sizing';
import { computeFinancials } from '@/lib/financials';
import { synthesiseRoofGeometry, inferProfileFromLocation } from '@/lib/customRoof';
import type {
  CustomerProfile,
  DesignResult,
  HouseId,
  RoofGeometry,
} from '@/lib/types';

const MODULE_WATT_PEAK = 475;
const MODULE_BRAND: 'AIKO' | 'Trina' = 'AIKO';
const INVERTER_MODEL = 'SMA Tripower X';
const BATTERY_BRAND = 'BYD HVS';
const HEATPUMP_MODEL = 'Viessmann Vitocal 250-A';
const PANEL_EFFICIENCY = 0.18;

interface DesignRequestBody {
  houseId: HouseId | 'custom';
  profile?: CustomerProfile;
  lat?: number;
  lng?: number;
  address?: string;
}

function isSouthish(azimuthDeg: number): boolean {
  return azimuthDeg > 90 && azimuthDeg < 270;
}

async function loadBakedGeometry(houseId: HouseId): Promise<RoofGeometry> {
  const filePath = path.join(process.cwd(), 'public', 'baked', `${houseId}-analysis.json`);
  const raw = await fs.readFile(filePath, 'utf-8');
  return JSON.parse(raw) as RoofGeometry;
}

export async function POST(req: NextRequest) {
  const t0 = performance.now();

  let body: DesignRequestBody;
  try {
    body = (await req.json()) as DesignRequestBody;
  } catch {
    return NextResponse.json({ error: 'Invalid JSON body' }, { status: 400 });
  }
  const { houseId } = body;
  if (!houseId) {
    return NextResponse.json({ error: 'Missing houseId' }, { status: 400 });
  }

  // 1. Resolve profile (provided, or inferred for custom)
  let profile: CustomerProfile | undefined = body.profile;
  if (!profile && houseId === 'custom') {
    profile = inferProfileFromLocation(body.lat, body.lng);
  }
  if (!profile) {
    return NextResponse.json({ error: 'Missing profile' }, { status: 400 });
  }

  // 2. Resolve roof geometry
  let roof: RoofGeometry;
  let synthesised = false;
  if (houseId === 'custom') {
    roof = synthesiseRoofGeometry(body.lat ?? 0, body.lng ?? 0, profile.houseSizeSqm);
    synthesised = true;
  } else {
    try {
      roof = await loadBakedGeometry(houseId);
    } catch {
      return NextResponse.json(
        { error: `No analysis.json for house "${houseId}"` },
        { status: 404 },
      );
    }
  }

  // 3. Compute the maximum solar capacity the roof can host (south-ish faces only).
  //    isJumelee → divide by 2 (shared roof with neighbour).
  const houseShareDivisor = profile.isJumelee ? 2 : 1;
  const southFaces = roof.faces.filter((f) => isSouthish(f.azimuth));
  const rawRoofMaxKwp =
    southFaces.reduce((sum, f) => sum + f.usableArea * PANEL_EFFICIENCY, 0)
    || roof.faces.reduce((sum, f) => sum + f.usableArea * PANEL_EFFICIENCY, 0);
  const roofMaxKwp = rawRoofMaxKwp / houseShareDivisor;

  // 4. k-NN sizing on the 1620 Reonic projects
  const reco = await recommendSystem(profile, roofMaxKwp);

  // 5. Module count + inverter sizing
  const moduleCount = Math.max(1, Math.round((reco.totalKwp * 1000) / MODULE_WATT_PEAK));
  const inverterPowerKw = Math.max(1, Math.ceil(reco.totalKwp * 0.85));

  // 6. Financials
  const fin = computeFinancials({
    totalKwp: reco.totalKwp,
    batteryKwh: reco.batteryCapacityKwh,
    heatPumpKw: reco.heatPumpNominalPowerKw,
    hasWallbox: profile.hasEv,
    annualConsumptionKwh: profile.annualConsumptionKwh,
    hasEv: profile.hasEv,
  });

  // 7. Trim modulePositions if k-NN sized us below the roof maximum.
  const baseModulePositions = roof.modulePositions ?? [];
  const targetCount = Math.min(moduleCount, baseModulePositions.length);
  const modulePositions = targetCount > 0
    ? baseModulePositions.slice(0, targetCount)
    : baseModulePositions;

  const result: DesignResult = {
    moduleCount: modulePositions.length || moduleCount,
    moduleBrand: MODULE_BRAND,
    moduleWattPeak: MODULE_WATT_PEAK,
    totalKwp: reco.totalKwp,
    modulePositions,

    inverterModel: INVERTER_MODEL,
    inverterPowerKw,
    inverterLoadPercent: Math.round((reco.totalKwp / inverterPowerKw) * 100),

    batteryCapacityKwh: reco.batteryCapacityKwh,
    batteryBrand: BATTERY_BRAND,

    heatPumpModel: reco.heatPumpNominalPowerKw ? HEATPUMP_MODEL : null,
    heatPumpNominalPowerKw: reco.heatPumpNominalPowerKw,

    wallboxChargeSpeedKw: profile.hasEv ? 11 : null,

    totalPriceEur: fin.totalPriceEur,
    paybackYears: fin.paybackYears,
    co2SavedTonsPer25y: fin.co2SavedTonsPer25y,

    similarProjects: reco.similarProjects,
    deltaVsMedian: reco.deltaVsMedian,

    source: reco.source,
    inferenceMs: Math.round(performance.now() - t0),

    geometry: synthesised ? roof : undefined,
  };

  return NextResponse.json(result);
}

// Zustand state machine — OWNED by Dev C
// Read freely from anywhere. Writes only via the action methods below.

import { create } from 'zustand';
import type {
  AppPhase,
  HouseId,
  CustomerProfile,
  DesignRefinements,
  DesignResult,
  RoofGeometry,
  AgentStep,
} from './types';

// Custom address selected via Google Places Autocomplete on landing.
// Other devs (B = backend, A = scene, D = geometry) read this when
// `selectedHouse === 'custom'` to drive their own runtime pipeline.
export interface CustomAddress {
  formatted: string;          // e.g. "12 Lindenstraße, 14467 Brandenburg, Germany"
  lat: number;
  lng: number;
  placeId?: string;           // Google place_id, for caching/dedup if needed
  countryCode?: string;       // ISO 3166-1 alpha-2 (e.g. "DE")
}

// Manual questionnaire inputs (only meaningful when selectedHouse === 'custom')
// Mirrors the Reonic onboarding flow exactly.
export type CalculateBy = 'usage' | 'cost';
export type Currency = 'EUR' | 'GBP' | 'USD';
export type HeatingFamily = 'renewable' | 'conventional';
export type PvPackage = 'starter' | 'comfort' | 'premium';
export type BatteryPackage = 'starter' | 'comfort' | 'premium';
export type ChargerPackage = 'comfort';

export interface ManualInputs {
  // Energy consumption
  calculateBy: CalculateBy;
  consumptionKwh: number;        // residential consumption
  inhabitants: number;           // 1-4+ (people selector)
  electricityPrice: number;      // p/kWh or cents/kWh
  currency: Currency;
  annualIncreasePct: number;     // default 3
  timeOfUsePrices: boolean;
  // Existing solar
  hasSolar: boolean | null;
  // Heating
  heatingFamily: HeatingFamily | null;
  // EV
  hasEv: boolean | null;
  evModel?: string;              // free text e.g. "Elaris · Beo"
  evAnnualKm?: number;
  // EV Charger
  hasEvCharger: boolean | null;
  // PV package selection (Reonic offer step)
  selectedPackage: PvPackage | null;
  selectedBattery: BatteryPackage | null;
  selectedCharger: ChargerPackage | null;
  // Section completion flags (controls Save → collapsed summary)
  saved: {
    energy: boolean;
    solar: boolean;
    heating: boolean;
    ev: boolean;
    charger: boolean;
  };
}

export type TrellisStatus = 'idle' | 'generating' | 'ready' | 'error';

/** A user-editable panel. After auto-placement settles, <Panels/> hydrates
 *  `editedPanels` from the computed layout, then the user can add / remove /
 *  drag panels in edit mode. `quaternion` is recomputed from `normal` at
 *  render time so we don't need to serialise it. */
export interface EditablePanel {
  id: string;
  x: number;
  y: number;
  z: number;
  normal: [number, number, number];
}

interface AppState {
  // Phase
  phase: AppPhase;
  setPhase: (phase: AppPhase) => void;

  // Trellis (image-to-3D) generation status. Written by Orchestrator as it
  // walks the capture → clean → trellis chain; read by TrellisModel (which
  // shows the GLB once ready) and the design page overlays (which only
  // mount once the scene is interactive).
  trellisStatus: TrellisStatus;
  setTrellisStatus: (s: TrellisStatus) => void;

  // URL of the generated GLB (set by Orchestrator when fal-ai/trellis
  // returns). TrellisModel watches this to load the mesh into the scene.
  glbUrl: string | null;
  setGlbUrl: (u: string | null) => void;

  /** Set to `true` by <LoadedGlb/> after the GLTFLoader has finished
   *  loading the mesh. Means the GLB is parsed and mounted, but the
   *  skeleton→GLB cross-fade may still be running. */
  glbLoaded: boolean;
  setGlbLoaded: (v: boolean) => void;

  /** Set to `true` by <MorphingBuilding/> after the skeleton→GLB cross-fade
   *  is COMPLETE and the GLB is fully visible at scale 1.0. This is the
   *  signal the panel-drop animation gates on — guarantees we never start
   *  laying panels onto a still-morphing or invisible roof. */
  glbStable: boolean;
  setGlbStable: (v: boolean) => void;

  /** Rendered Y height of the GLB after the uniform XZ scale applied by
   *  <LoadedGlb/>. Used by <HouseGeometryProvider/> to rescale baked panel
   *  positions onto the actual roof — different houses have different roof
   *  pitches, so the analysis.json baseline doesn't match the GLB by default. */
  glbHeight: number | null;
  setGlbHeight: (v: number | null) => void;

  /** Total number of panels actually fitted on the GLB roof by the variant
   *  cascade in <Panels/>. Published so the orchestrator's drop-animation
   *  loop knows when to stop (k-NN's target count can differ from this if
   *  the algorithm chose a compact variant for a tight roof). */
  panelTargetCount: number;
  setPanelTargetCount: (v: number) => void;

  /** Total upward-facing roof area on the rendered GLB (sum of triangles
   *  whose world normal Y > 0.5), in square meters. Computed once after the
   *  GLB is in the scene so we can size panels relative to actual roof
   *  capacity and report coverage in the KPI sidebar. */
  glbRoofAreaM2: number | null;
  setGlbRoofAreaM2: (v: number | null) => void;

  /** Rendered XZ bbox of the GLB (post-scale), in meters. Lets the panel
   *  packer know the world-space footprint to scan. */
  glbBboxXZ: { width: number; depth: number } | null;
  setGlbBboxXZ: (v: { width: number; depth: number } | null) => void;

  // House selection — either a demo HouseId or 'custom' for an arbitrary address.
  selectedHouse: HouseId | 'custom' | null;
  selectHouse: (id: HouseId | 'custom') => void;

  // Custom address (only meaningful when selectedHouse === 'custom')
  customAddress: CustomAddress | null;
  setCustomAddress: (a: CustomAddress | null) => void;

  // Manual questionnaire inputs (custom address flow)
  manualInputs: ManualInputs;
  updateManualInput: <K extends keyof ManualInputs>(
    key: K,
    value: ManualInputs[K],
  ) => void;
  saveManualSection: (section: keyof ManualInputs['saved']) => void;
  resetManualInputs: () => void;

  // Customer profile (auto-filled, then editable)
  profile: CustomerProfile | null;
  setProfile: (p: CustomerProfile) => void;
  updateProfileField: <K extends keyof CustomerProfile>(
    key: K,
    value: CustomerProfile[K],
  ) => void;

  // Refinements (post-design)
  refinements: DesignRefinements;
  setRefinement: <K extends keyof DesignRefinements>(
    key: K,
    value: DesignRefinements[K],
  ) => void;

  // Design result (from /api/design)
  design: DesignResult | null;
  setDesign: (d: DesignResult | null) => void;

  /**
   * Number of panels currently revealed in the placement animation. Starts
   * at 0 once the imagery + sizing lanes have settled, then ticks up to
   * `design.modulePositions.length` over a few seconds. <Panels/> slices the
   * positions array by this count so only the first N panels render.
   */
  placedCount: number;
  setPlacedCount: (n: number) => void;

  /** Manual-edit overlay over the auto-generated layout. `null` means "use
   *  the auto layout as-is". Once the user touches the layout (toggles edit
   *  mode, adds/removes/drags a panel) <Panels/> hydrates this with the
   *  auto-generated panels and switches to rendering from this list. */
  editedPanels: EditablePanel[] | null;
  setEditedPanels: (p: EditablePanel[] | null) => void;
  addEditedPanel: (p: EditablePanel) => void;
  removeEditedPanel: (id: string) => void;
  updateEditedPanel: (id: string, patch: Partial<Omit<EditablePanel, 'id'>>) => void;
  resetEditedPanels: () => void;

  /** When true, panels are interactive: click to delete, drag to reposition,
   *  click on bare roof to add. <Panels/> reads this; <ControlPanel/> writes it. */
  panelEditMode: boolean;
  setPanelEditMode: (v: boolean) => void;

  // Roof geometry — usually loaded from /baked/{houseId}-analysis.json by
  // HouseGeometryProvider. For custom addresses, /api/design synthesises one
  // and we stash it here so the Scene3D consumes it directly.
  customRoofGeometry: RoofGeometry | null;
  setCustomRoofGeometry: (g: RoofGeometry | null) => void;

  // Agent sequence
  agentSteps: AgentStep[];
  setAgentSteps: (s: AgentStep[]) => void;
  updateStepStatus: (id: string, status: AgentStep['status']) => void;
  /** Patch any subset of fields on a single step (artifactUrl, resultLine, …). */
  updateStepFields: (id: string, fields: Partial<AgentStep>) => void;

  // Reset
  reset: () => void;
}

const defaultRefinements: DesignRefinements = {
  includeBattery: true,
  includeHeatPump: true,
  includeWallbox: false,
};

const defaultManualInputs: ManualInputs = {
  calculateBy: 'usage',
  consumptionKwh: 3500,
  inhabitants: 3,
  electricityPrice: 35,
  currency: 'EUR',
  annualIncreasePct: 3,
  timeOfUsePrices: false,
  hasSolar: null,
  heatingFamily: null,
  hasEv: null,
  evModel: undefined,
  evAnnualKm: 15000,
  hasEvCharger: null,
  selectedPackage: null,
  selectedBattery: null,
  selectedCharger: null,
  saved: {
    energy: false,
    solar: false,
    heating: false,
    ev: false,
    charger: false,
  },
};

export const useStore = create<AppState>((set) => ({
  phase: 'idle',
  setPhase: (phase) => set({ phase }),

  trellisStatus: 'idle',
  setTrellisStatus: (trellisStatus) => set({ trellisStatus }),

  glbUrl: null,
  setGlbUrl: (glbUrl) =>
    set({ glbUrl, glbLoaded: false, glbStable: false, glbHeight: null }),

  glbLoaded: false,
  setGlbLoaded: (glbLoaded) => set({ glbLoaded }),

  glbStable: false,
  setGlbStable: (glbStable) => set({ glbStable }),

  glbHeight: null,
  setGlbHeight: (glbHeight) => set({ glbHeight }),

  panelTargetCount: 0,
  setPanelTargetCount: (panelTargetCount) => set({ panelTargetCount }),

  glbRoofAreaM2: null,
  setGlbRoofAreaM2: (glbRoofAreaM2) => set({ glbRoofAreaM2 }),

  glbBboxXZ: null,
  setGlbBboxXZ: (glbBboxXZ) => set({ glbBboxXZ }),

  selectedHouse: null,
  selectHouse: (id) =>
    set({ selectedHouse: id, phase: 'house-selected', trellisStatus: 'idle', glbUrl: null }),

  customAddress: null,
  setCustomAddress: (customAddress) => set({ customAddress }),

  manualInputs: defaultManualInputs,
  updateManualInput: (key, value) =>
    set((s) => ({ manualInputs: { ...s.manualInputs, [key]: value } })),
  saveManualSection: (section) =>
    set((s) => ({
      manualInputs: {
        ...s.manualInputs,
        saved: { ...s.manualInputs.saved, [section]: true },
      },
    })),
  resetManualInputs: () => set({ manualInputs: defaultManualInputs }),

  profile: null,
  setProfile: (profile) => set({ profile }),
  updateProfileField: (key, value) =>
    set((s) => ({ profile: s.profile ? { ...s.profile, [key]: value } : null })),

  refinements: defaultRefinements,
  setRefinement: (key, value) =>
    set((s) => ({ refinements: { ...s.refinements, [key]: value } })),

  design: null,
  setDesign: (design) => set({ design, editedPanels: null }),

  placedCount: 0,
  setPlacedCount: (placedCount) => set({ placedCount }),

  editedPanels: null,
  setEditedPanels: (editedPanels) => set({ editedPanels }),
  addEditedPanel: (p) =>
    set((s) => ({ editedPanels: [...(s.editedPanels ?? []), p] })),
  removeEditedPanel: (id) =>
    set((s) => ({
      editedPanels: s.editedPanels
        ? s.editedPanels.filter((p) => p.id !== id)
        : s.editedPanels,
    })),
  updateEditedPanel: (id, patch) =>
    set((s) => ({
      editedPanels: s.editedPanels
        ? s.editedPanels.map((p) => (p.id === id ? { ...p, ...patch } : p))
        : s.editedPanels,
    })),
  resetEditedPanels: () => set({ editedPanels: null }),

  panelEditMode: false,
  setPanelEditMode: (panelEditMode) => set({ panelEditMode }),

  customRoofGeometry: null,
  setCustomRoofGeometry: (customRoofGeometry) => set({ customRoofGeometry }),

  agentSteps: [],
  setAgentSteps: (agentSteps) => set({ agentSteps }),
  updateStepStatus: (id, status) =>
    set((s) => ({
      agentSteps: s.agentSteps.map((step) =>
        step.id === id ? { ...step, status } : step,
      ),
    })),
  updateStepFields: (id, fields) =>
    set((s) => ({
      agentSteps: s.agentSteps.map((step) =>
        step.id === id ? { ...step, ...fields } : step,
      ),
    })),

  reset: () =>
    set({
      phase: 'idle',
      trellisStatus: 'idle',
      glbUrl: null,
      selectedHouse: null,
      customAddress: null,
      manualInputs: defaultManualInputs,
      profile: null,
      refinements: defaultRefinements,
      design: null,
      customRoofGeometry: null,
      agentSteps: [],
      placedCount: 0,
      glbLoaded: false,
      glbStable: false,
      glbHeight: null,
      panelTargetCount: 0,
      glbRoofAreaM2: null,
      glbBboxXZ: null,
      editedPanels: null,
      panelEditMode: false,
    }),
}));

