// matches Google Solar API's reference panel for fair area comparisons.
// Env-overridable knobs (used by analyze-multi.ts variants).
const numEnv = (name: string, def: number): number => {
  const v = process.env[name];
  return v !== undefined && !Number.isNaN(parseFloat(v)) ? parseFloat(v) : def;
};

const MODULE_WIDTH_M = 1.045;
const MODULE_HEIGHT_M = 1.879;
// Industry typical eaves/ridge offset is ~30-40 cm.
const EDGE_OFFSET_M = numEnv('VARIANT_EDGE_OFFSET_M', 0.3);
const MODULE_GAP_M = 0.02;

interface ModulePosition {
  x: number;
  y: number;
  z: number;
  faceId: number;
}

/**
 * Optional shade-aware filter. Given a candidate panel position in world
 * coords, returns the fraction of sample sun positions where this point is
 * blocked by the photogrammetry mesh (0 = always sunlit, 1 = always shaded).
 *
 * Optionally also estimates the annual direct-beam flux (kWh/m²/yr) for the
 * given panel position + normal — used by analyze-roof to drop panels whose
 * combined orientation + shading puts them below a yield threshold.
 */
export interface ShadeSampler {
  shadedFraction(x: number, y: number, z: number): number;
  annualFlux?(x: number, y: number, z: number, normal: [number, number, number]): number;
}

const MAX_SHADED_FRACTION = numEnv('VARIANT_MAX_SHADED_FRACTION', 0.30);

/**
 * Place modules on a single roof face on a regular grid.
 * Steps:
 *   1. Build a local frame on the face (normal = z, plus tangent + bitangent).
 *   2. Project the polygon vertices to 2D in that frame.
 *   3. Shrink the polygon by `EDGE_OFFSET_M` (per-edge inset).
 *   4. Tile a (W+gap) × (H+gap) grid across the polygon AABB.
 *   5. Keep cells whose center is inside the inset polygon AND outside every obstruction.
 *   6. Project each kept center back to world coords.
 */
export function placePanelsOnFace(
  face: RoofFace,
  obstructions: Obstruction[],
  maxModules?: number,
  shadeSampler?: ShadeSampler,
): ModulePosition[] {
  if (!face.vertices || face.vertices.length < 3) return [];

  const normal = new THREE.Vector3().fromArray(face.normal).normalize();
  const origin = new THREE.Vector3().fromArray(face.vertices[0] as [number, number, number]);

  // Pick a stable tangent: take an edge of the polygon, project it onto the face plane.
  const edgeWorld = new THREE.Vector3()
    .fromArray(face.vertices[1] as [number, number, number])
    .sub(origin);
  const tangent = edgeWorld.clone().sub(normal.clone().multiplyScalar(edgeWorld.dot(normal))).normalize();
  const bitangent = new THREE.Vector3().crossVectors(normal, tangent).normalize();

  // World → local 2D
  const toLocal = (p: number[]): { u: number; v: number } => {
    const w = new THREE.Vector3().fromArray(p as [number, number, number]).sub(origin);
    return { u: w.dot(tangent), v: w.dot(bitangent) };
  };
  const toWorld = (u: number, v: number): THREE.Vector3 =>
    origin
      .clone()
      .add(tangent.clone().multiplyScalar(u))

