3	
4	export type HouseId = 'brandenburg' | 'hamburg' | 'ruhr';
5	
6	export type HeatingType = 'oil' | 'gas' | 'heatpump' | 'other';
7	
8	// Customer profile inputs (auto-filled then editable)
9	export interface CustomerProfile {
10	  annualConsumptionKwh: number; // e.g. 4500
11	  inhabitants: number;          // 1-6
12	  hasEv: boolean;
13	  evAnnualKm?: number;          // e.g. 15000
14	  heatingType: HeatingType;
15	  houseSizeSqm: number;
16	  isJumelee: boolean;           // semi-detached (Doppelhaus): roof shared with neighbour → /api/design divides usable area by 2
17	}
18	
19	// Refinement toggles (post-design)
20	export interface DesignRefinements {
21	  includeBattery: boolean;
22	  includeHeatPump: boolean;
23	  includeWallbox: boolean;
