'use client';

import { motion, useSpring, useTransform } from 'framer-motion';
import { useEffect } from 'react';
import { useStore } from '@/lib/store';
import type { HouseId } from '@/lib/types';

// Real-world panel surface area, used to translate the placed panel count
// into m² of roof covered. Defaults to AIKO 475 W (~1.95 m²) — the cascade
// in <Panels/> picks compact / mini for tight roofs but the area tends to
// land in the same ballpark since smaller panels need higher counts.
const PANEL_AREA_M2 = 1.722 * 1.134;

const HOUSE_LOCATION: Record<HouseId, string> = {
  brandenburg: 'Thielallee 36, Berlin, Germany',
  hamburg: 'Test addr 2, Potsdam-Golm, Germany',
  ruhr: 'Schönerlinder Weg 83, Berlin Karow, Germany',
};

export function KPISidebar() {
  const design = useStore((s) => s.design);
  const profile = useStore((s) => s.profile);
  // panelTargetCount = MAX number of panels DevD's algorithm could physically
  // fit on the roof (variant cascade upper bound). DevB's `design.moduleCount`
  // is the k-NN-sized count (matched against 1 620 historical Reonic
  // deliveries) — the customer-facing default. Once the user enters
  // edit-layout mode, `editedPanels.length` overrides both.
  const editedPanels = useStore((s) => s.editedPanels);
  const efficientPanelCount = design?.moduleCount ?? 0;
  const liveCount = editedPanels?.length ?? efficientPanelCount;
  const setPanelEditMode = useStore((s) => s.setPanelEditMode);
  const phase = useStore((s) => s.phase);
  const canEdit = phase === 'interactive';
  const glbRoofAreaM2 = useStore((s) => s.glbRoofAreaM2);
  const selectedHouse = useStore((s) => s.selectedHouse);
  const customAddress = useStore((s) => s.customAddress);
  const address =
    selectedHouse && selectedHouse !== 'custom'
      ? HOUSE_LOCATION[selectedHouse]
      : customAddress?.formatted ?? null;

  const totalKwp = design?.totalKwp ?? 0;
  const battery = design?.batteryCapacityKwh ?? 0;
  const price = design?.totalPriceEur ?? 0;
  const payback = design?.paybackYears ?? 0;
  const co2 = design?.co2SavedTonsPer25y ?? 0;
  const consumption = profile?.annualConsumptionKwh ?? 0;
  const evKm = profile?.hasEv ? profile.evAnnualKm ?? 0 : 0;
  const evKwh = Math.round(evKm * 0.18);
  const residentialKwh = Math.max(0, consumption - evKwh);

  const panelArea = liveCount * PANEL_AREA_M2;
  const roofCoveragePct =
    glbRoofAreaM2 && glbRoofAreaM2 > 0
      ? Math.min(100, Math.round((panelArea / glbRoofAreaM2) * 100))
      : 0;

  // Live from /api/design's computeFinancials. Depends on system composition
  // (battery / heat pump / EV) — not a hardcoded constant.
  const ownConsumptionPct = Math.round((design?.selfConsumptionRatio ?? 0) * 100);

  return (
    <motion.div
      initial={{ opacity: 0, x: 16 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ duration: 0.35 }}
      className="overflow-hidden rounded-3xl border border-zinc-200/70 bg-white shadow-[0_8px_28px_-12px_rgba(0,0,0,0.18)]"
    >
      {/* Header */}
      <div className="border-b border-zinc-100 px-5 py-3.5">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="text-[14px] font-bold tracking-tight text-zinc-900">Your design</h3>
            <p className="text-[11px] text-zinc-500">k-NN match · 1 620 deliveries</p>
          </div>
          <span className="rounded-full bg-emerald-50 px-2 py-0.5 text-[10px] font-semibold text-emerald-700">
            Live
          </span>
        </div>
        {address && (
          <div className="mt-2 flex items-start gap-1.5 text-[11px] text-zinc-500" title={address}>
            <svg className="mt-0.5 h-3 w-3 flex-shrink-0 text-zinc-400" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z" />
              <circle cx="12" cy="10" r="3" />
            </svg>
            <span className="truncate">{address}</span>
          </div>
        )}
      </div>

      {/* Top KPIs grid 2×2 */}
      <div className="grid grid-cols-2 gap-px bg-zinc-100">
        <BigKpi
          value={consumption}
          decimals={0}
          suffix=" kWh"
          label="Power consumption"
          sub={`${residentialKwh.toLocaleString()} kWh residential${evKwh ? ` + ${evKwh.toLocaleString()} kWh e-car` : ''}`}
        />
        <BigKpi
          value={price}
          decimals={0}
          prefix="€"
          label="Total investment"
          sub="One-time, incl. installation"
        />
        <BigKpi
          value={payback}
          decimals={1}
          suffix=" yrs"
          label="Break-even"
          sub="vs. grid baseline"
          accent="emerald"
        />
        <BigKpi
          value={ownConsumptionPct}
          decimals={0}
          suffix="%"
          label="Own consumption"
          sub="self-sufficiency"
          accent="blue"
        />
      </div>

      {/* Compact line items */}
      <div className="space-y-2.5 px-5 py-4">
        <CompactKpi icon={<SunIcon />} tone="blue" label="System power" value={totalKwp} suffix=" kWp" decimals={1} />
        {battery > 0 && (
          <CompactKpi icon={<BatteryIcon />} tone="emerald" label="Battery" value={battery} suffix=" kWh" decimals={1} />
        )}
        {glbRoofAreaM2 != null && liveCount > 0 && (
          <div className="flex items-center gap-2">
            <div className="flex-1">
              <CompactKpi
                icon={<RoofIcon />}
                tone="blue"
                label={`Roof · ${liveCount} panels (${roofCoveragePct}%)`}
                value={panelArea}
                suffix={` / ${glbRoofAreaM2.toFixed(0)} m²`}
                decimals={1}
              />
            </div>
            {canEdit && (
              <button
                onClick={() => setPanelEditMode(true)}
                title="Edit panel layout"
                className="flex h-7 items-center gap-1 rounded-md border border-blue-200 bg-blue-50 px-2 text-[11px] font-semibold text-blue-700 transition hover:border-blue-300 hover:bg-blue-100"
              >
                <svg className="h-3 w-3" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M12 20h9" />
                  <path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4Z" />
                </svg>
                Edit
              </button>
            )}
          </div>
        )}
        <CompactKpi icon={<LeafIcon />} tone="emerald" label="CO₂ saved · 25 yrs" value={co2} suffix=" tons" decimals={1} />
      </div>
    </motion.div>

