2081	function ResultDashboard() {
2082	  const m = useStore((s) => s.manualInputs);
2083	  const [detailOpen, setDetailOpen] = useState(false);
2084	
2085	  const sym: Record<Currency, string> = { EUR: '€', GBP: '£', USD: '$' };
2086	  const currency = sym[m.currency];
2087	  const unitPrice = m.electricityPrice / 100; // ct/kWh → €/kWh
2088	
2089	  const evKwh = m.hasEv && m.evAnnualKm ? Math.round((m.evAnnualKm * 20) / 100) : 0;
2090	  const totalKwh = m.consumptionKwh + evKwh;
2091	  const residentialCost = Math.round(m.consumptionKwh * unitPrice);
2092	  const evCost = Math.round(evKwh * unitPrice);
2093	  const totalCostBefore = residentialCost + evCost;
2094	
2095	  // Approximations driven by user choices.
2096	  const hasBattery = !!m.selectedBattery;
2097	  const hasCharger = !!m.selectedCharger;
2098	
2099	  // Self-sufficiency:
2100	  //  - Base solar coverage of residential ≈ 38 %
2101	  //  - +Battery shifts evening load to stored solar (~+25 pts)
2102	  //  - +EV without smart charger: EV charges off-peak from grid (~−8 pts)
2103	  //  - +EV with smart charger: charges during solar hours (~+7 pts)
2104	  const baseSelfSuff = hasBattery ? 63 : 38;
2105	  const chargerBoost = m.hasEv && hasCharger ? 7 : 0;
2106	  const evGridPenalty = m.hasEv && !hasCharger ? -8 : 0;
2107	  const selfSufficiency = Math.max(15, Math.min(85, baseSelfSuff + chargerBoost + evGridPenalty));
2108	
2109	  const costAfter = Math.round(totalCostBefore * (1 - selfSufficiency / 100));
2110	  const yieldOver20 = (totalCostBefore - costAfter) * 20;
2111	
2112	  // Break-even climbs with each upfront capex (battery, charger).
2113	  const baseYears = m.selectedPackage === 'starter' ? 8 : m.selectedPackage === 'comfort' ? 11 : 14;
2114	  const breakEvenYears = baseYears + (hasBattery ? 2 : 0) + (hasCharger ? 1 : 0);
2115	  const co2Tons = Math.round(totalKwh * 0.0004 * 10) / 10;
2116	  const trees = Math.round(co2Tons * 41);
