29	const MODULE_BRAND: 'AIKO' | 'Trina' = 'AIKO';
30	const INVERTER_MODEL = 'SMA Tripower X';
31	const BATTERY_BRAND = 'BYD HVS';
32	const HEATPUMP_MODEL = 'Viessmann Vitocal 250-A';
33	const PANEL_EFFICIENCY = 0.18;
34	
