1	// Real-time view of the 3 actual pipeline steps (CAPTURE → SIZE → MODEL).
2	// Driven entirely by the AgentStep[] in the store, which Orchestrator.tsx
3	// updates as each underlying promise resolves. No fake durations, no fake
4	// substeps — what you see is what's actually happening.
5	
6	'use client';
7	
8	import { AnimatePresence, motion } from 'framer-motion';
9	import { useEffect, useRef, useState } from 'react';
10	import { useStore } from '@/lib/store';
11	import type { AgentStep } from '@/lib/types';
12	
13	// How long the centre-screen popup stays visible before morphing into the
14	// step's slot. Long enough to read but still snappy on cached runs.
15	const POPUP_HOLD_MS = 1300;
16	
17	export function AgentTrace() {
18	  const steps = useStore((s) => s.agentSteps);
19	
20	  // Single-popup queue: ensures popups always appear in top-down step order,
21	  // even if `size` (parallel lane) finishes before `capture`/`clean`. When
22	  // the active popup closes after POPUP_HOLD_MS, the next eligible step's
23	  // popup opens. `shownIds` powers two things: the queue's "already done"
24	  // check, and gating each card's in-slot artifact so it only appears once
25	  // the morph is ready to land (not during the upstream wait).
26	  const [shownIds, setShownIds] = useState<Set<string>>(new Set());
27	  const [activePopupId, setActivePopupId] = useState<string | null>(null);
28	
29	  // Reset memory when the pipeline restarts.
30	  useEffect(() => {
31	    const anyDone = steps.some((s) => s.status === 'done');
32	    if (!anyDone && (shownIds.size > 0 || activePopupId)) {
33	      setShownIds(new Set());
34	      setActivePopupId(null);
35	    }
36	  }, [steps, shownIds, activePopupId]);
37	
38	  // Queue: when no popup is active, pick the next eligible step.
39	  useEffect(() => {
40	    if (activePopupId) return;
41	    const next = steps.find((s, i) => {
42	      if (s.status !== 'done') return false;
43	      if (shownIds.has(s.id)) return false;
44	      if (!s.artifactUrl && !s.resultLine) return false;
45	      for (let j = 0; j < i; j++) {
46	        const earlier = steps[j];
47	        if (earlier.status !== 'done' && earlier.status !== 'error') return false;
48	        const earlierEligible = !!earlier.artifactUrl || !!earlier.resultLine;
49	        if (earlierEligible && !shownIds.has(earlier.id)) return false;
50	      }
51	      return true;
52	    });
53	    if (next) setActivePopupId(next.id);
