1	// POST /api/export — OWNED by Dev B
2	// Generates a 1-page A4 PDF "Quick Offer" from a DesignResult + canvas screenshot.
3	// Returned as application/pdf binary so the browser downloads it directly.
4	
5	import { NextRequest, NextResponse } from 'next/server';
6	import { jsPDF } from 'jspdf';
7	import type { DesignResult, CustomerProfile } from '@/lib/types';
8	
9	interface ExportBody {
10	  profile: CustomerProfile;
11	  design: DesignResult;
12	  canvasDataUrl?: string;     // r3f screenshot from gl.domElement.toDataURL('image/png')
13	  installerName?: string;
14	  customerName?: string;
15	  address?: string;
16	}
17	
18	const REONIC_GREEN: [number, number, number] = [38, 145, 100];
19	const DARK_TEXT: [number, number, number] = [30, 30, 30];
20	const MUTED_TEXT: [number, number, number] = [110, 110, 110];
21	
22	export async function POST(req: NextRequest) {
23	  let body: ExportBody;
24	  try {
25	    body = (await req.json()) as ExportBody;
26	  } catch {
27	    return NextResponse.json({ error: 'Invalid JSON body' }, { status: 400 });
28	  }
29	  const { profile, design, canvasDataUrl, installerName, customerName, address } = body;
30	  if (!profile || !design) {
31	    return NextResponse.json({ error: 'Missing profile or design' }, { status: 400 });
32	  }
33	
34	  const doc = new jsPDF({ format: 'a4', unit: 'mm' });
35	  const PAGE_W = 210;
36	  let y = 18;
37	
38	  // --- Header ---
39	  doc.setTextColor(...REONIC_GREEN);
40	  doc.setFont('helvetica', 'bold');
41	  doc.setFontSize(22);
42	  doc.text('Iconic', 20, y);
43	  doc.setTextColor(...DARK_TEXT);
44	  doc.setFont('helvetica', 'normal');
45	  doc.setFontSize(11);
46	  doc.text('Quick Solar Offer', 47, y);
47	
48	  doc.setTextColor(...MUTED_TEXT);
49	  doc.setFontSize(8);
50	  doc.text(`Generated ${new Date().toLocaleDateString('de-DE')} · ${new Date().toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' })}`, PAGE_W - 20, y, { align: 'right' });
51	
52	  // Horizontal rule
53	  y += 4;
54	  doc.setDrawColor(220, 220, 220);
55	  doc.line(20, y, PAGE_W - 20, y);
56	
57	  // --- Customer block ---
58	  y += 7;
59	  doc.setTextColor(...DARK_TEXT);
60	  doc.setFont('helvetica', 'bold');
61	  doc.setFontSize(10);
62	  doc.text(customerName ?? 'Customer', 20, y);
63	  doc.setFont('helvetica', 'normal');
64	  if (address) {
65	    y += 5;
66	    doc.setTextColor(...MUTED_TEXT);
67	    doc.setFontSize(9);
68	    doc.text(address, 20, y);
69	  }
70	  y += 5;
71	  doc.setTextColor(...MUTED_TEXT);
72	  doc.setFontSize(8);
73	  doc.text(
74	    `${profile.inhabitants} inhabitants · ${profile.houseSizeSqm} m² · ${profile.annualConsumptionKwh.toLocaleString('de-DE')} kWh/yr · heating: ${profile.heatingType}${profile.hasEv ? ' · EV' : ''}`,
75	    20,
76	    y,
77	  );
78	
79	  // --- Canvas screenshot ---
80	  y += 8;
81	  if (canvasDataUrl && canvasDataUrl.startsWith('data:image/')) {
82	    try {
83	      const fmt = canvasDataUrl.startsWith('data:image/jpeg') ? 'JPEG' : 'PNG';
84	      doc.addImage(canvasDataUrl, fmt, 20, y, PAGE_W - 40, 80);
85	      y += 82;
86	    } catch {
87	      // skip if image fails to embed
88	    }
89	  }
90	
91	  // --- Bill of Materials block ---
92	  y += 4;
93	  doc.setTextColor(...REONIC_GREEN);
94	  doc.setFont('helvetica', 'bold');
95	  doc.setFontSize(11);
96	  doc.text('Bill of Materials', 20, y);
97	  y += 6;
98	  doc.setTextColor(...DARK_TEXT);
99	  doc.setFont('helvetica', 'normal');
100	  doc.setFontSize(9);
101	
102	  const bomLines: { label: string; value: string }[] = [
103	    {
104	      label: 'Solar modules',
105	      value: `${design.moduleCount}× ${design.moduleBrand} ${design.moduleWattPeak}Wp = ${design.totalKwp} kWp`,
106	    },
107	    {
108	      label: 'Inverter',
109	      value: `${design.inverterModel} ${design.inverterPowerKw} kW (${design.inverterLoadPercent}% load)`,
110	    },
111	    design.batteryCapacityKwh != null
112	      ? { label: 'Battery storage', value: `${design.batteryCapacityKwh} kWh ${design.batteryBrand}` }
113	      : null,
114	    design.heatPumpModel
115	      ? { label: 'Heat pump', value: `${design.heatPumpModel} ${design.heatPumpNominalPowerKw} kW` }
116	      : null,
117	    design.wallboxChargeSpeedKw != null
118	      ? { label: 'Wallbox', value: `${design.wallboxChargeSpeedKw} kW EV charger` }
119	      : null,
120	  ].filter((x): x is { label: string; value: string } => x !== null);
121	
122	  for (const line of bomLines) {
123	    doc.setTextColor(...MUTED_TEXT);
124	    doc.text(line.label, 25, y);
125	    doc.setTextColor(...DARK_TEXT);
126	    doc.text(line.value, 70, y);
127	    y += 5;
128	  }
129	
130	  // --- Financials (right-aligned KPI strip) ---
131	  y += 5;
132	  doc.setDrawColor(230, 230, 230);
133	  doc.line(20, y, PAGE_W - 20, y);
134	  y += 8;
135	
136	  doc.setFont('helvetica', 'bold');
137	  doc.setFontSize(18);
138	  doc.setTextColor(...REONIC_GREEN);
139	  const totalText = `€${design.totalPriceEur.toLocaleString('de-DE')}`;
140	  doc.text(totalText, 20, y);
141	
142	  doc.setFont('helvetica', 'normal');
143	  doc.setFontSize(8);
144	  doc.setTextColor(...MUTED_TEXT);
145	  doc.text('Total system price (installed)', 20, y + 4);
146	
147	  // KPI columns
148	  doc.setFont('helvetica', 'bold');
149	  doc.setFontSize(13);
150	  doc.setTextColor(...DARK_TEXT);
151	  const kpiY = y;
152	  doc.text(`${design.paybackYears} yrs`, 95, kpiY);
153	  doc.text(`${design.co2SavedTonsPer25y} t`, 140, kpiY);
154	  doc.text(`${design.totalKwp} kWp`, 175, kpiY);
155	
156	  doc.setFont('helvetica', 'normal');
157	  doc.setFontSize(7);
158	  doc.setTextColor(...MUTED_TEXT);
159	  doc.text('Payback', 95, kpiY + 4);
160	  doc.text('CO₂ saved (25y)', 140, kpiY + 4);
161	  doc.text('Capacity', 175, kpiY + 4);
162	
163	  // --- Reonic evidence (similar projects) ---
164	  y += 14;
165	  doc.setTextColor(...REONIC_GREEN);
166	  doc.setFont('helvetica', 'bold');
167	  doc.setFontSize(10);
168	  doc.text(`Validated against ${design.similarProjects.length} similar Iconic deliveries`, 20, y);
169	  y += 5;
170	  doc.setTextColor(...MUTED_TEXT);
171	  doc.setFont('helvetica', 'normal');
172	  doc.setFontSize(8);
173	  const deltaSign = design.deltaVsMedian.kwp >= 0 ? '+' : '';
174	  doc.text(
175	    `Δ vs median: ${deltaSign}${design.deltaVsMedian.kwp} kWp · battery ${deltaSign}${design.deltaVsMedian.batteryKwh} kWh`,
176	    20,
177	    y,
178	  );
