  y += 8;
  if (canvasDataUrl && canvasDataUrl.startsWith('data:image/')) {
    try {
      const fmt = canvasDataUrl.startsWith('data:image/jpeg') ? 'JPEG' : 'PNG';
      doc.addImage(canvasDataUrl, fmt, 20, y, PAGE_W - 40, 80);
      y += 82;
    } catch {
      // skip if image fails to embed
