(() => {
  const canvases = document.querySelectorAll('canvas');
  // Walk the R3F scene graph to count instances of each component.
  // Look at THREE.Scene via the canvas's __r3f property.
  const cv = canvases[0];
  const root = cv?.__r3f?.fiber || null;
  if (!root) return JSON.stringify({error: 'r3f root not found'});
  const counts = { 'gltf-primitive': 0, 'mesh': 0, 'group': 0 };
  const labels = [];
  // Check three scene
  const scene = cv.parentElement?.parentElement;
  // Simpler: directly query the THREE scene from store keys we have
  const objects = [];
  const gl = window.__r3fState?.gl || null;
  // Try querying the actual scene
  const inverter = !!document.querySelector('[data-inverter]');
  return JSON.stringify({
    canvases: canvases.length,
    canvas_size: cv ? `${cv.width}x${cv.height}` : null,
    r3f_root: !!root
  });
})()

(() => {
  // Find the THREE.Scene by looking at the captureSnapshot fn registered in the store
  const cap = window.__store?.getState?.().captureSnapshot;
  // captureSnapshot was registered with closures over gl/scene/camera. We can't access those directly.
  // Instead, find the canvas and traverse its parents.
  const canvas = document.querySelector('canvas');
  if (!canvas) return 'no canvas';
  // Use captureSnapshot to verify the gl is alive
  const snap = cap?.();
  return JSON.stringify({
    canvas_present: true,
    canvas_w: canvas.width,
    canvas_h: canvas.height,
    snapshot_first_120: snap?.slice(0, 120) ?? null
  });
})()

(() => {
  // Crawl through React fibers from the canvas's parent to find the R3F root state
  const canvas = document.querySelector('canvas');
  let fiberKey = Object.keys(canvas).find(k => k.startsWith('__reactFiber') || k.startsWith('__reactInternalInstance'));
  if (!fiberKey) return 'no fiber on canvas';
  let fiber = canvas[fiberKey];
  let scene = null, camera = null;
  // Walk up the fiber tree looking for an internal R3F state
  let depth = 0;
  while (fiber && depth < 80) {
    const memoState = fiber.memoizedState;
    const memoProps = fiber.memoizedProps;
    if (memoState?.scene && memoState.scene.isScene) { scene = memoState.scene; camera = memoState.camera; break; }
    if (memoProps?.scene && memoProps.scene.isScene) { scene = memoProps.scene; camera = memoProps.camera; break; }
    if (fiber.stateNode?.scene?.isScene) { scene = fiber.stateNode.scene; break; }
    fiber = fiber.return;
    depth++;
  }
  if (!scene) return 'no scene found in fiber walk depth ' + depth;
  // Walk the scene to count interesting things
  let mesh = 0, gltfRoots = 0, groups = 0, names = [];
  scene.traverse(o => {
    if (o.type === 'Mesh') mesh++;
    if (o.type === 'Group') groups++;
    if (o.userData?.gltfExtensions || o.userData?.glb) gltfRoots++;
    if (o.name && !names.includes(o.name) && names.length < 25) names.push(o.name);
  });
  return JSON.stringify({mesh, gltfRoots, groups, total: scene.children.length, names});
})()

